func:
// Outbox Enqueue v1 - Step 1
const config = global.get("config") || {};
const out = msg.outbox || {};
const type = out.type;
const payload = out.payload;

if (!type) throw new Error("Outbox Enqueue: missing msg.outbox.type");
if (!payload || typeof payload !== "object") throw new Error("Outbox Enqueue: missing/invalid msg.outbox.payload");

// Where to send later (Publisher will use this)
const endpointByType = {
  cycle: "/api/ingest/cycle",
  event: "/api/ingest/event",
  kpi: "/api/ingest/kpi",
  heartbeat: "/api/ingest/heartbeat",
  segment: "/api/ingest/segment", // future; ok to queue now even if not used yet
};

const endpoint = out.endpoint || endpointByType[type];
if (!endpoint) throw new Error(`Outbox Enqueue: unknown type '${type}' and no endpoint provided`);

// Get machineId from msg or global config
const machineId = msg.machineId || config.machineId;
if (!machineId) {
  node.status({ fill: "yellow", shape: "ring", text: "Outbox waiting for pairing" });
  return null;
}

const schemaVersion = msg.schemaVersion || "1.0";
const tsMs = typeof msg.tsMs === "number" ? msg.tsMs : Date.now();

// Stash meta for later nodes
msg._outboxMeta = { type, endpoint, machineId, schemaVersion, tsMs, payload };

const validators = {
  cycle: (p) => p && typeof p.cycle === "object",
  event: (p) => p && typeof p.event === "object",
  kpi: (p) => p && p.kpis && typeof p.kpis === "object",
  heartbeat: (p) => p && typeof p.status === "string",
  segment: (p) => p && typeof p === "object",
};

const validator = validators[type];
if (!validator || !validator(payload)) {
  node.warn(`Outbox Enqueue: invalid ${type} payload`);
  return null;
}

// Call stored procedure to get next seq (safe + persistent)
msg.topic = "CALL next_seq(?);";
msg.payload = [machineId];

return msg;

// Outbox Enqueue v1 - Step 2
const meta = msg._outboxMeta;
if (!meta) throw new Error("Outbox Enqueue: missing _outboxMeta");

function stripNil(obj) {
  if (!obj || typeof obj !== "object") return obj;
  const out = Array.isArray(obj) ? [] : {};
  for (const [k, v] of Object.entries(obj)) {
    if (v === undefined || v === null) continue;   // <— key change
    out[k] = (v && typeof v === "object") ? stripNil(v) : v;
  }
  return out;
}

// Parse seq from MySQL result
// mysql node often returns an array of result sets for CALL
let seq = null;
const res = msg.payload;

if (Array.isArray(res)) {
  // common shape: [ [ { seq: 123 } ], ... ]
  if (Array.isArray(res[0]) && res[0][0] && res[0][0].seq != null) seq = res[0][0].seq;
  // sometimes: [ { seq: 123 } ]
  if (seq == null && res[0] && res[0].seq != null) seq = res[0].seq;
}

if (seq == null) throw new Error("Outbox Enqueue: could not parse seq from DB result");




function normalizeIsoDeep(obj) {
  if (!obj || typeof obj !== "object") return obj;
  if (Array.isArray(obj)) return obj.map(normalizeIsoDeep);

  for (const k of Object.keys(obj)) {
    const v = obj[k];

    // recurse first
    if (v && typeof v === "object") obj[k] = normalizeIsoDeep(v);

    // ISO fields: must be string|null
    if (k.toLowerCase().endsWith("iso")) {
      const vv = obj[k];
      if (typeof vv === "string") continue;
      if (typeof vv === "number") obj[k] = new Date(vv).toISOString();
      else if (vv == null) obj[k] = null;
      else obj[k] = null; // <- kills {} forever
    }
  }
  return obj;
}





const cleanPayload = normalizeIsoDeep(stripNil(meta.payload));
const envelope = {
  schemaVersion: meta.schemaVersion,
  machineId: meta.machineId,
  tsMs: meta.tsMs,
  seq: String(seq),
  type: meta.type,
  payload: cleanPayload
};


// Prepare insert into outbox_messages
msg.topic = `
INSERT INTO outbox_messages
(machine_id, msg_type, endpoint, schema_version, seq, ts_device_ms, payload_json, status, attempts, next_attempt_at)
VALUES (?, ?, ?, ?, ?, ?, ?, 'pending', 0, NULL);
`.trim();

msg.payload = [
  meta.machineId,
  meta.type,
  meta.endpoint,
  meta.schemaVersion,
  Number(seq),          // BIGINT
  meta.tsMs,      // BIGINT
  JSON.stringify(envelope),
];

// Keep a copy for debugging
msg._envelope = envelope;
msg._seq = Number(seq);

return msg;

if (msg.ui_control && msg.ui_control.tab) {
    msg.payload = { tab: msg.ui_control.tab };
    delete msg.ui_control;
    return msg;
}
return null;

// Handle anomaly acknowledgments and downtime-reason submit.
// Output 1: SQL update for anomaly_events
// Output 2: event payload for Build Event Outbox Payload
const anomaly = global.get("anomaly") || {};
const topic = msg.topic || "";

function persistAnomaly(next) {
    global.set("anomaly", next);
    try {
        global.set("anomaly", next, "file");
    } catch (err) {
        // ignore if file store is not configured
    }
}

function parseReason(payload) {
    const reasonPath = Array.isArray(payload.reasonPath) ? payload.reasonPath : [];
    const category = reasonPath[0] || {};
    const detail = reasonPath[1] || {};
    return {
        type: payload.reasonType || "downtime",
        categoryId: category.id || null,
        categoryLabel: category.label || null,
        detailId: detail.id || null,
        detailLabel: detail.label || null,
        reasonText: payload.reasonText || [
            category.label || "",
            detail.label || ""
        ].filter(Boolean).join(" > ") || null,
        catalogVersion: payload.catalogVersion || null,
        incidentKey: payload.incidentKey || payload.incident_key || null
    };
}

function removeFromActive(eventId) {
    let activeAnomalies = anomaly.activeAnomalies || [];
    const idx = activeAnomalies.findIndex((a) => a.event_id === eventId || a.tsMs === eventId);
    if (idx !== -1) {
        activeAnomalies.splice(idx, 1);
        anomaly.activeAnomalies = activeAnomalies;
    }
}

if (topic === "acknowledge-anomaly" || topic === "anomaly-reason-submit") {
    const ackData = msg.payload || {};
    const eventId = ackData.event_id ?? ackData.tsMs;
    const ackTimestamp = typeof ackData.tsMs === "number" ? ackData.tsMs : Date.now();
    const incidentKey = ackData.incidentKey || ackData.incident_key || null;

    if (!eventId) {
        node.warn("[ANOMALY ACK] No event_id provided");
        return null;
    }

    if (String(eventId).startsWith("temp_")) {
        removeFromActive(eventId);
        persistAnomaly(anomaly);
        return null;
    }

    const sql = (
        "UPDATE anomaly_events " +
        "SET status = 'acknowledged', acknowledged_at = " + Number(ackTimestamp) + " " +
        "WHERE event_timestamp = " + Number(eventId)
    );
    const dbMsg = { topic: sql, payload: [] };

    removeFromActive(eventId);

    if (topic === "anomaly-reason-submit") {
        anomaly.reasonsByIncident = anomaly.reasonsByIncident || {};
        anomaly.ackedIncidentKeys = anomaly.ackedIncidentKeys || {};

        const reason = parseReason(ackData);
        if (incidentKey) {
            anomaly.reasonsByIncident[incidentKey] = reason;
            anomaly.ackedIncidentKeys[incidentKey] = true;
        }

        persistAnomaly(anomaly);

        const alreadySent = !!(incidentKey && anomaly.reasonEventsSent && anomaly.reasonEventsSent[incidentKey]);
        if (alreadySent) {
            return [dbMsg, null];
        }

        if (incidentKey) {
            anomaly.reasonEventsSent = anomaly.reasonEventsSent || {};
            anomaly.reasonEventsSent[incidentKey] = true;
            persistAnomaly(anomaly);
        }

        const eventTsMs = Number(ackData.tsMs) || Date.now();
        const anomalyType = ackData.anomalyType || ackData.anomaly_type || "downtime";
        const outEvent = {
            tsMs: eventTsMs,
            eventType: "downtime-acknowledged",
            anomalyType,
            eventId: eventId,
            incidentKey: incidentKey || null,
            // Keep reason attached to generic event payload for current ingest.
            reason,
            // Explicit separation for future split in Control Tower.
            downtime: {
                incidentKey: incidentKey || null,
                eventId: eventId,
                anomalyType,
                acknowledgedAtMs: eventTsMs,
                reason
            }
        };

        return [{ ...dbMsg }, { payload: outEvent, tsMs: eventTsMs }];
    }

    if (incidentKey) {
        anomaly.ackedIncidentKeys = anomaly.ackedIncidentKeys || {};
        anomaly.ackedIncidentKeys[incidentKey] = true;
    }
    persistAnomaly(anomaly);

    return [dbMsg, null];
}

return null;

// Get current global value (default to 0 if not set)
const state = global.get("state") || {};
let estado = state.machineToggle || 0;
let stop = flow.get('stop') || false;

if (stop) {
    // Manual stop active → force 0, don't reschedule
    state.machineToggle = 0;
global.set("state", state);
    msg.payload = 0;
    node.send(msg);
    return;
}

// Toggle between 1 and 0
estado = estado === 1 ? 0 : 1;

// Update the global variable
state.machineToggle = estado;
global.set("state", state);

// Send it out
msg.payload = estado;
return msg;

const settings = global.get("settings") || {};
const state = global.get("state") || {};
const moldByWorkOrder = state.moldByWorkOrder || {};

const persistSettings = () => {
    global.set("settings", settings);
    try {
        global.set("settings", settings, "file");
    } catch (err) {
        // ignore if file store is not configured
    }
};

const persistMoldCache = () => {
    const cache = {
        lastMoldActive: state.lastMoldActive ?? null,
        lastMoldTotal: state.lastMoldTotal ?? null,
        moldByWorkOrder: state.moldByWorkOrder || {}
    };
    global.set("moldCache", cache);
    try {
        global.set("moldCache", cache, "file");
    } catch (err) {
        // ignore if file store is not configured
    }
};

const persistState = () => {
    global.set("state", state);
};

const persistMoldSelection = (total, active) => {
    if (!Number.isFinite(active) || active <= 0) return;
    state.lastMoldActive = active;
    if (Number.isFinite(total) && total > 0) {
        state.lastMoldTotal = total;
    }
    if (state.activeWorkOrder?.id) {
        state.activeWorkOrder.cavities = active;
        if (Number.isFinite(total) && total > 0) {
            state.activeWorkOrder.cavities_total = total;
        }
        moldByWorkOrder[state.activeWorkOrder.id] = {
            total: Number.isFinite(total) && total > 0 ? total : (state.lastMoldTotal ?? null),
            active
        };
    }
    state.moldByWorkOrder = moldByWorkOrder;
    persistState();
    persistMoldCache();
};

const buildCavitiesUpdate = (total, active) => {
    const activeId = state.activeWorkOrder?.id;
    if (!activeId || !Number.isFinite(active) || active <= 0) return null;
    const totalSafe = Number.isFinite(total) && total > 0 ? total : 0;
    return {
        topic: "UPDATE work_orders SET cavities_total = COALESCE(NULLIF(?,0), cavities_total), cavities_active = COALESCE(NULLIF(?,0), cavities_active), updated_at = NOW() WHERE work_order_id = ?",
        payload: [totalSafe, active, activeId]
    };
};

if (msg.topic === "moldSettings" && msg.payload) {
    const total = Number(msg.payload.total || 0);
    const active = Number(msg.payload.active || 0);

    // Store settings
    settings.moldTotal = total;
    settings.moldActive = active;
    persistSettings();

    persistMoldSelection(total, active);

    node.status({ fill: "green", shape: "dot", text: `Saved: ${active}/${total}` });

    const dbMsg = buildCavitiesUpdate(total, active);

    msg.payload = { saved: true, total, active };
    return [msg, dbMsg];
}

// Handle preset selection
if (msg.topic === "selectMoldPreset" && msg.payload) {
    const preset = msg.payload;
    const total = Number(preset.theoretical_cavities || 0);
    const active = Number(preset.functional_cavities || 0);

    // Store settings
    settings.moldTotal = total;
    settings.moldActive = active;
    persistSettings();

    persistMoldSelection(total, active);

    node.status({ fill: "blue", shape: "dot", text: `Preset: ${preset.mold_name}` });

    // Send to UI to update fields
    msg.topic = "moldPresetSelected";
    msg.payload = { total, active, presetName: preset.mold_name };

    const dbMsg = buildCavitiesUpdate(total, active);

    return [msg, dbMsg];
}

//node.status({ fill: "red", shape: "ring", text: "Invalid payload" });
return [null, null];

const topic = msg.topic || '';
const payload = msg.payload || {};

// ===== IGNORE NON-MOLD TOPICS SILENTLY =====
// These are KPI/dashboard messages not meant for this handler
const ignoredTopics = [
    'machineStatus',
    'kpis',
    'chartsData',
    'activeWorkOrder',
    'workOrderCycle',
    'workOrdersList',
    'scrapPrompt',
    'uploadStatus'
];

if (ignoredTopics.includes(topic) || topic === '') {
    return null;  // Silent ignore
}

// Log only mold-related requests
node.warn(`Received: ${topic}`);

// CRITICAL: Use a processing lock to prevent simultaneous requests
let dedupeKey = topic;
if (topic === 'addMoldPreset') {
    dedupeKey = `add_${payload.manufacturer}_${payload.mold_name}`;
} else if (topic === 'getMoldsByManufacturer') {
    dedupeKey = `getmolds_${payload.manufacturer}`;
}

const lockKey = `lock_${dedupeKey}`;
const lastRequestKey = `last_request_${dedupeKey}`;

// Check if currently processing this request
if (flow.get(lockKey) === true) {
    node.warn(`${topic} already processing - duplicate blocked`);
    return null;
}

// Check timing
const now = Date.now();
const lastRequestTime = flow.get(lastRequestKey) || 0;
if (now - lastRequestTime < 2000) {
    node.warn(`Duplicate ${topic} request ignored (within 2s)`);
    return null;
}

// Set lock IMMEDIATELY before any async operations
flow.set(lockKey, true);
flow.set(lastRequestKey, now);

// Release lock after 3 seconds (safety timeout)
setTimeout(() => {
    flow.set(lockKey, false);
}, 3000);

// Load all presets (legacy)
if (topic === 'loadMoldPresets') {
    msg._originalTopic = 'loadMoldPresets';
    msg.topic = 'SELECT * FROM mold_presets ORDER BY manufacturer, mold_name;';
    node.warn('Querying all presets');
    return msg;
}

// Search/filter presets (legacy)
if (topic === 'searchMoldPresets') {
    const filters = msg.payload || {};
    const searchTerm = (filters.searchTerm || '').trim().replace(/['\"\\\\]/g, '');
    const manufacturer = (filters.manufacturer || '').replace(/['\"\\\\]/g, '');
    const theoreticalCavities = filters.theoreticalCavities || '';

    let query = 'SELECT * FROM mold_presets WHERE 1=1';

    if (searchTerm) {
        const searchPattern = `%${searchTerm}%`;
        query += ` AND (mold_name LIKE '${searchPattern.replace(/'/g, "''")}' OR manufacturer LIKE '${searchPattern.replace(/'/g, "''")}')`;
    }

    if (manufacturer && manufacturer !== 'All') {
        query += ` AND manufacturer = '${manufacturer.replace(/'/g, "''")}'`;
    }

    if (theoreticalCavities && theoreticalCavities !== '') {
        const cavities = Number(theoreticalCavities);
        if (!isNaN(cavities)) {
            query += ` AND theoretical_cavities = ${cavities}`;
        }
    }

    query += ' ORDER BY manufacturer, mold_name;';

    msg._originalTopic = 'searchMoldPresets';
    msg.topic = query;
    return msg;
}

// Get unique manufacturers for dropdown
if (topic === 'getManufacturers') {
    msg._originalTopic = 'getManufacturers';
    msg.topic = 'SELECT DISTINCT manufacturer FROM mold_presets ORDER BY manufacturer;';
    node.warn('Querying manufacturers');
    return msg;
}

// Get molds for a specific manufacturer
if (topic === 'getMoldsByManufacturer') {
    const data = msg.payload || {};
    const manufacturerRaw = (data.manufacturer || '').trim();
    if (!manufacturerRaw) {
        node.warn('No manufacturer provided');
        return null;
    }

    const manufacturerSafe = manufacturerRaw.replace(/['\"\\\\]/g, '').replace(/'/g, "''");

    msg._originalTopic = 'getMoldsByManufacturer';
    msg.topic = `SELECT * FROM mold_presets WHERE manufacturer = '${manufacturerSafe}' ORDER BY mold_name;`;
    node.warn(`Querying molds for: ${manufacturerSafe}`);
    return msg;
}

// Add a new mold preset - CRITICAL: Strong deduplication
if (topic === 'addMoldPreset') {
    const data = msg.payload || {};
    const manufacturerRaw = (data.manufacturer || '').trim();
    const moldNameRaw = (data.mold_name || '').trim();
    const theoreticalRaw = (data.theoretical || '').trim();
    const activeRaw = (data.active || '').trim();

    if (!manufacturerRaw || !moldNameRaw || !theoreticalRaw || !activeRaw) {
        node.status({ fill: 'red', shape: 'ring', text: 'Missing value' });
        node.warn('Missing required fields');
        return null;
    }

    // Additional safety check for already-processed flag
    if (msg._addMoldProcessed) {
        node.warn('addMoldPreset already processed flag detected, ignoring');
        return null;
    }
    msg._addMoldProcessed = true;

    const manufacturerSafe = manufacturerRaw.replace(/['\"\\\\]/g, '').replace(/'/g, "''");
    const moldNameSafe = moldNameRaw.replace(/['\"\\\\]/g, '').replace(/'/g, "''");
    const theoreticalSafe = theoreticalRaw.replace(/['\"\\\\]/g, '').replace(/'/g, "''");
    const activeSafe = activeRaw.replace(/['\"\\\\]/g, '').replace(/'/g, "''");

    msg._originalTopic = 'addMoldPreset';
    msg.topic =
        "INSERT INTO mold_presets (manufacturer, mold_name, theoretical_cavities, functional_cavities) " +
        "VALUES ('" + manufacturerSafe + "', '" + moldNameSafe + "', " + theoreticalSafe + ", " + activeSafe + ");";

    node.status({ fill: 'blue', shape: 'dot', text: 'Inserting mold...' });
    node.warn(`Inserting: ${manufacturerSafe} - ${moldNameSafe}`);
    return msg;
}

node.warn(`Unknown topic: ${topic}`);
return null;

// Replace function in "Process DB Results" node

const originalTopic = msg._originalTopic || '';
const dbResults = Array.isArray(msg.payload) ? msg.payload : [];

if (!originalTopic) {
    return null;
}

// IMPORTANT: Clear socketid to prevent loops back to sender
delete msg._socketid;
delete msg.socketid;

// Manufacturers query → list for first dropdown
if (originalTopic === 'getManufacturers') {
    const manufacturers = dbResults
        .map(row => row.manufacturer)
        .filter((mfg, index, arr) => mfg && arr.indexOf(mfg) === index)
        .sort();

    msg.topic = 'manufacturersList';
    msg.payload = manufacturers;

    node.status({ fill: 'green', shape: 'dot', text: `${manufacturers.length} manufacturers` });
    return msg;
}

// Preset lists (legacy load/search)
if (originalTopic === 'loadMoldPresets' || originalTopic === 'searchMoldPresets') {
    const presets = dbResults.map(row => ({
        mold_name: row.mold_name || '',
        manufacturer: row.manufacturer || '',
        theoretical_cavities: Number(row.theoretical_cavities) || 0,
        functional_cavities: Number(row.functional_cavities) || 0
    }));

    msg.topic = 'moldPresetsList';
    msg.payload = presets;

    node.status({ fill: 'green', shape: 'dot', text: `${presets.length} presets found` });
    return msg;
}

// Molds for selected manufacturer
if (originalTopic === 'getMoldsByManufacturer') {
    const presets = dbResults.map(row => ({
        mold_name: row.mold_name || '',
        manufacturer: row.manufacturer || '',
        theoretical_cavities: Number(row.theoretical_cavities) || 0,
        functional_cavities: Number(row.functional_cavities) || 0
    }));

    msg.topic = 'moldPresetsList';
    msg.payload = presets;

    node.status({ fill: 'blue', shape: 'dot', text: `${presets.length} molds for manufacturer` });
    return msg;
}

// Result of inserting a new mold
if (originalTopic === 'addMoldPreset') {
    msg.topic = 'addMoldResult';
    msg.payload = {
        success: true,
        result: msg.payload
    };

    node.status({ fill: 'green', shape: 'dot', text: 'Mold added' });
    return msg;
}

node.status({ fill: 'yellow', shape: 'ring', text: 'Unknown topic: ' + originalTopic });
return null;

const config = global.get("config") || {};
const settings = global.get("settings") || {};
const state = global.get("state") || {};
const reasonCatalog = settings.reasonCatalog || {};

// ✨ La WO de la BD es la única fuente de cavidades.
// attachMold solo normaliza nombres (cavities/cavitiesActive, cavities_total/cavitiesTotal)
// para que el resto del código pueda leerlos con cualquier alias.
// YA NO escribe en state.lastMoldActive ni state.moldByWorkOrder (cache global eliminado).
const attachMold = (order) => {
    if (!order || !order.id) return;

    const cavities = Number(
        order.cavitiesActive ??
        order.cavities_active ??
        order.cavities ??
        0
    );
    const total = Number(
        order.cavitiesTotal ??
        order.cavities_total ??
        0
    );

    if (Number.isFinite(cavities) && cavities > 0) {
        order.cavitiesActive = cavities;
        order.cavities = cavities; // alias para código viejo
    }
    if (Number.isFinite(total) && total > 0) {
        order.cavitiesTotal = total;
        order.cavities_total = total; // alias para código viejo
    }
};

const finalize = (ret) => {
    global.set("state", state);
    return ret;
};

const normalizeReason = (payload, fallbackType) => {
    const path = Array.isArray(payload.reasonPath) ? payload.reasonPath : [];
    const category = path[0] || {};
    const detail = path[1] || {};
    return {
        type: payload.reasonType || fallbackType || "downtime",
        categoryId: category.id || null,
        categoryLabel: category.label || null,
        detailId: detail.id || null,
        detailLabel: detail.label || null,
        reasonText: payload.reasonText || [
            category.label || "",
            detail.label || ""
        ].filter(Boolean).join(" > ") || null,
        catalogVersion: payload.catalogVersion || reasonCatalog.version || null,
        incidentKey: payload.incidentKey || null
    };
};


// ===== MOLD CHANGE AUTO-CLOSE =====
// If a mold change is active and user is starting/resuming/restarting a WO, close it.
if (state.moldChange && state.moldChange.active &&
    (msg.action === "start" || msg.action === "start-work-order" || msg.action === "resume-work-order" || msg.action === "restart-work-order")) {
    const now = Date.now();
    const mc = state.moldChange;
    const durationSec = Math.max(0, Math.round((now - (mc.startMs || now)) / 1000));
    const closedMc = {
        active: false,
        startMs: mc.startMs,
        endMs: now,
        fromMoldId: mc.fromMoldId || null,
        toMoldId: null,
        durationSec
    };
    state.moldChange = closedMc;
    global.set("state", state);
    const closeEvent = {
        payload: {
            anomaly_type: "mold-change",
            eventType: "mold-change",
            severity: "info",
            requires_ack: false,
            title: "Cambio de molde finalizado (automatico)",
            description: "Duracion: " + Math.round(durationSec / 60) + " min",
            status: "resolved",
            tsMs: now,
            data: {
                status: "resolved",
                start_ms: closedMc.startMs,
                end_ms: now,
                duration_sec: durationSec,
                stoppage_duration_seconds: durationSec,
                from_mold_id: closedMc.fromMoldId,
                to_mold_id: closedMc.toMoldId,
                incidentKey: "mold-change:" + (closedMc.startMs || now)
            }
        },
        tsMs: now
    };
    const uiClose = { _mode: "mold-change-status", payload: { active: false, endMs: now, durationSec } };
    node.send([null, uiClose, null, null, null, closeEvent]);
}

const mode = msg._mode || '';
switch (msg.action) {
    case "upload-excel":
        msg._mode = "upload";
        return finalize([msg, null, null, null]);
    case "refresh-work-orders": {
        const selectMsg = {
            ...msg,
            _mode: "select",
            topic: "SELECT * FROM work_orders ORDER BY created_at DESC;"
        };
        const fetchMsg = {
            ...msg,
            topic: "workOrdersRefresh",
            forceRefresh: true,
            payload: msg.payload && typeof msg.payload === "object" ? msg.payload : {}
        };
        return finalize([null, selectMsg, null, null, null, null, fetchMsg]);
    }
    case "start-work-order": {
        msg._mode = "start-check-progress";
        const order = msg.payload || {};
        if (!order.id) {
            node.error("No work order id supplied for start", msg);
            return finalize([null, null, null, null]);
        }

        // ✨ FIX: pausar inmediatamente la WO actual antes de cargar la nueva.
        // Previene que se sumen ciclos a la WO anterior mientras llega el resume-prompt.
        if (state.activeWorkOrder && state.activeWorkOrder.id !== order.id) {
            node.warn(`[START-WO] Pausando WO actual ${state.activeWorkOrder.id} antes de cargar ${order.id}`);
            state.trackingEnabled = false;
            state.productionStarted = false;
            flow.set("lastMachineState", 0);

            // ✨ También sincronizar state.lastState para que el polling cada 500ms
            // del HMI (get-current-state) no devuelva valores viejos al template
            // y reactive el botón DETENER.
            if (state.lastState && typeof state.lastState === "object") {
                state.lastState = {
                    ...state.lastState,
                    trackingEnabled: false,
                    productionStarted: false,
                    tsMs: Date.now()
                };
            }
        }
        flow.set("pendingWorkOrder", order);

        msg.topic = "SELECT cycle_count, good_parts, scrap_parts, progress_percent, target_qty, cavities_total, cavities_active FROM work_orders WHERE work_order_id = ? LIMIT 1";
        msg.payload = [order.id];

        return finalize([null, msg, null, null]);
    }
    case "resume-work-order": {
        const now = Date.now();
        state.productionStartTime = now;
        state.actualRunTime = 0;
        state.lastStartChangeTime = now;
        state.runSeconds = 0;
        state.stopSeconds = 0;
        state.kpiLastTick = null;
        msg._mode = "resume";
        const order = msg.payload || {};
        if (!order.id) {
            node.error("No work order id supplied for resume", msg);
            return finalize([null, null, null, null]);
        }

        // Set status to RUNNING without resetting progress
        msg.topic = "UPDATE work_orders SET status = CASE WHEN work_order_id = ? THEN 'RUNNING' ELSE 'PENDING' END, updated_at = CASE WHEN work_order_id = ? THEN NOW() ELSE updated_at END, cavities_total = COALESCE(NULLIF(?,0), cavities_total), cavities_active = COALESCE(NULLIF(?,0), cavities_active) WHERE status <> 'DONE'";
        // ✨ Acepta cavitiesActive (nuevo) o cavities (alias viejo)
        msg.payload = [
            order.id,
            order.id,
            Number(order.cavitiesTotal || order.cavities_total || 0),
            Number(order.cavitiesActive || order.cavities_active || order.cavities || 0)
        ];
        msg.startOrder = order;

        // Load existing values into global state
        order.scrapParts = Number(order.scrapParts) || 0;
        order.goodParts = Number(order.goodParts) || 0;

        attachMold(order);

        state.activeWorkOrder = order;
        state.cycleCount = Number(order.cycleCount) || 0;
        state.activeOrderHasProgress = true;
        flow.set("lastMachineState", 0);
        state.scrapPromptIssuedFor = null;

        return finalize([null, null, msg, null]);
    }
    case "restart-work-order": {
        const now = Date.now();
        state.productionStartTime = now;
        state.actualRunTime = 0;
        state.lastStartChangeTime = now;
        state.runSeconds = 0;
        state.stopSeconds = 0;
        state.kpiLastTick = null;
        msg._mode = "restart";
        const order = msg.payload || {};
        if (!order.id) {
            node.error("No work order id supplied for restart", msg);
            return finalize([null, null, null, null]);
        }

        // Reset progress in database AND set status to RUNNING
        msg.topic = "UPDATE work_orders SET status = CASE WHEN work_order_id = ? THEN 'RUNNING' ELSE 'PENDING' END, cycle_count = 0, good_parts = 0, scrap_parts = 0, progress_percent = 0, updated_at = NOW(), cavities_total = COALESCE(NULLIF(?,0), cavities_total), cavities_active = COALESCE(NULLIF(?,0), cavities_active) WHERE work_order_id = ? OR status = 'RUNNING'";
        // ✨ Acepta cavitiesActive (nuevo) o cavities (alias viejo)
        msg.payload = [
            order.id,
            order.id,
            Number(order.cavitiesTotal || order.cavities_total || 0),
            Number(order.cavitiesActive || order.cavities_active || order.cavities || 0),
            order.id
        ];
        msg.startOrder = order;

        // Initialize global state to 0
        order.scrapParts = 0;
        order.goodParts = 0;

        attachMold(order);

        state.activeWorkOrder = order;
        state.cycleCount = 0;
        state.activeOrderHasProgress = false;
        flow.set("lastMachineState", 0);
        state.scrapPromptIssuedFor = null;

        return finalize([null, null, msg, null]);
    }
    case "complete-work-order": {
        state.productionStartTime = null;
        state.runSeconds = 0;
        state.stopSeconds = 0;
        state.kpiLastTick = null;
        msg._mode = "complete";
        const order = msg.payload || {};
        if (!order.id) {
            node.error("No work order id supplied for complete", msg);
            return finalize([null, null, null, null]);
        }

        // Get final values from global state before clearing
        const activeOrder = state.activeWorkOrder || {};
        const finalCycleCount = Number(state.cycleCount || 0);
        const finalGoodParts = Number(activeOrder.goodParts) || 0;
        const finalScrapParts = Number(activeOrder.scrapParts) || 0;

        msg.completeOrder = order;

        // SQL: Persist final counts AND set status to DONE
        msg.topic = "UPDATE work_orders SET status = 'DONE', cycle_count = ?, good_parts = ?, scrap_parts = ?, progress_percent = 100, updated_at = NOW() WHERE work_order_id = ?";
        msg.payload = [finalCycleCount, finalGoodParts, finalScrapParts, order.id];

        // Clear ALL state on completion
        state.activeWorkOrder = null;
        state.activeOrderHasProgress = false;
        state.trackingEnabled = false;
        state.productionStarted = false;
        state.kpiStartupMode = false;
        state.operatingTime = 0;
        state.lastCycleTime = null;
        state.cycleCount = 0;
        flow.set("lastMachineState", 0);
        state.scrapPromptIssuedFor = null;
        state.actualRunTime = 0;
        state.lastStateChangeTime = null;

        if (state.lastState && typeof state.lastState === "object") {
            state.lastState = {
                ...state.lastState,
                activeWorkOrder: null,
                cycleCount: 0,
                goodParts: 0,
                scrapParts: 0,
                cycleTime: 0,
                actualCycleTime: 0,
                trackingEnabled: false,
                productionStarted: false,
                tsMs: Date.now()
            };
        }

        // ============================================================
        // HIGH SCRAP DETECTION
        // ============================================================
        const targetQty = Number(activeOrder.target) || 0;
        const scrapCount = finalScrapParts;
        const scrapPercent = targetQty > 0 ? (scrapCount / targetQty) * 100 : 0;

        let anomalyMsg = null;
        if (scrapPercent > 10 && targetQty > 0) {
            const severity = scrapPercent > 25 ? 'critical' : 'warning';

            const highScrapAnomaly = {
                anomaly_type: 'high-scrap',
                severity: severity,
                title: `High Waste Detected`,
                description: `Work order completed with ${scrapCount} scrap parts (${scrapPercent.toFixed(1)}% of target ${targetQty}). Why is there so much waste?`,
                data: {
                    scrap_count: scrapCount,
                    target_quantity: targetQty,
                    scrap_percent: Math.round(scrapPercent * 10) / 10,
                    good_parts: finalGoodParts,
                    total_cycles: finalCycleCount
                },
                kpi_snapshot: {
                    oee: (msg.kpis && msg.kpis.oee) || state.currentKPIs?.oee || 0,
                    availability: (msg.kpis && msg.kpis.availability) || state.currentKPIs?.availability || 0,
                    performance: (msg.kpis && msg.kpis.performance) || state.currentKPIs?.performance || 0,
                    quality: (msg.kpis && msg.kpis.quality) || state.currentKPIs?.quality || 0
                },
                work_order_id: order.id,
                cycle_count: finalCycleCount,
                tsMs: Date.now(),
                status: 'active'
            };

            anomalyMsg = {
                topic: "anomaly-detected",
                payload: [highScrapAnomaly]
            };
        }

        return finalize([null, null, null, msg, anomalyMsg]);
    }
    case "get-current-state": {
        // Single truth for UI: state.lastState
        const s = state.lastState || {};

        const validWorkOrders = state.workOrdersById || null;
        if (state.activeWorkOrder?.id && validWorkOrders && !validWorkOrders[state.activeWorkOrder.id]) {
            node.warn(`[STATE] activeWorkOrder ${state.activeWorkOrder.id} not in work order list; clearing`);
            state.activeWorkOrder = null;
        }

        const activeOrder = (state.activeWorkOrder && state.activeWorkOrder.id)
            ? state.activeWorkOrder
            : null;

        const trackingEnabled =
            (typeof s.trackingEnabled === "boolean" ? s.trackingEnabled : (state.trackingEnabled || false));

        const productionStarted =
            (typeof s.productionStarted === "boolean" ? s.productionStarted : (state.productionStarted || false));

        const kpis =
            (s.kpis && typeof s.kpis === "object")
                ? s.kpis
                : (state.currentKPIs || { oee: 0, availability: 0, performance: 0, quality: 0 });

        // ✨ Las cavidades vienen ÚNICAMENTE de la WO activa (sin fallback al global cache)
        const cavities = Number(
            activeOrder?.cavitiesActive ??
            activeOrder?.cavities ??
            s.cavities ??
            0
        ) || null;

        msg._mode = "current-state";
        msg.payload = {
            machineId: s.machineId ?? config.machineId ?? undefined,

            activeWorkOrder: activeOrder,

            cycleCount: s.cycleCount,
            goodParts: s.goodParts,
            scrapParts: s.scrapParts,
            cavities,

            cycleTime: s.cycleTime,
            actualCycleTime: s.actualCycleTime,

            trackingEnabled,
            productionStarted,
            kpis,
            reasonCatalog,

            tsMs: s.tsMs
        };

        return finalize([null, msg, null, null]);
    }
    case "restore-session": {
        // Query DB for any RUNNING work order on startup
        msg._mode = "restore-query";
        msg.topic = "SELECT * FROM work_orders WHERE status = 'RUNNING' LIMIT 1";
        msg.payload = [];
        return finalize([null, msg, null, null]);
    }
    case "scrap-entry": {
        const { id, scrap } = msg.payload || {};
        const scrapNum = Number(scrap) || 0;

        if (!id) {
            node.error("No work order id supplied for scrap entry", msg);
            return finalize([null, null, null, null]);
        }

        const activeOrder = state.activeWorkOrder;
        if (activeOrder && activeOrder.id === id) {
            activeOrder.scrapParts = (Number(activeOrder.scrapParts) || 0) + scrapNum;
            state.activeWorkOrder = activeOrder;
        }

        state.scrapPromptIssuedFor = null;

        msg._mode = "scrap-update";
        msg.scrapEntry = { id, scrap: scrapNum, reason: null };
        msg.topic = "UPDATE work_orders SET scrap_parts = scrap_parts + ?, updated_at = NOW() WHERE work_order_id = ?";
        msg.payload = [scrapNum, id];

        return finalize([null, null, msg, null]);
    }
    case "scrap-entry-with-reason": {
        const { id, scrap } = msg.payload || {};
        const scrapNum = Number(scrap) || 0;
        const reason = normalizeReason(msg.payload || {}, "scrap");

        if (!id) {
            node.error("No work order id supplied for scrap entry with reason", msg);
            return finalize([null, null, null, null, null, null]);
        }

        const activeOrder = state.activeWorkOrder;
        if (activeOrder && activeOrder.id === id) {
            activeOrder.scrapParts = (Number(activeOrder.scrapParts) || 0) + scrapNum;
            state.activeWorkOrder = activeOrder;
        }

        state.scrapPromptIssuedFor = null;
        state.lastScrapReasonByOrder = state.lastScrapReasonByOrder || {};
        state.lastScrapReasonByOrder[id] = reason;

        const tsMs = Date.now();
        const outEvent = {
            tsMs,
            eventType: "scrap-manual-entry",
            workOrderId: id,
            scrapDelta: scrapNum,
            source: "home-ui",
            reason,
            downtime: null
        };

        msg._mode = "scrap-update";
        msg.scrapEntry = { id, scrap: scrapNum, reason };
        msg.topic = "UPDATE work_orders SET scrap_parts = scrap_parts + ?, updated_at = NOW() WHERE work_order_id = ?";
        msg.payload = [scrapNum, id];

        return finalize([null, null, msg, null, null, { payload: outEvent, tsMs }]);
    }
    case "scrap-open": {
        const active = state.activeWorkOrder || null;
        if (!active?.id) return finalize([null, null, null, null, null]);

        const good = Number(active.goodParts) || 0;
        const scrap = Number(active.scrapParts) || 0;
        const produced = good + scrap;

        msg._mode = "scrap-prompt";
        msg.scrapPrompt = {
            id: active.id,
            sku: active.sku || "",
            target: Number(active.target) || 0,
            produced,
            scrapSoFar: scrap,

            manual: true,
            title: "Registrar scrap (parcial)",
            enterMode: true,
            validateMax: false,
            reasonCatalog: reasonCatalog
        };

        delete msg.topic;
        delete msg.payload;

        return finalize([null, msg, null, null, null]);
    }
    case "scrap-skip": {
        const { id, remindAgain } = msg.payload || {};

        if (!id) {
            node.error("No work order id supplied for scrap skip", msg);
            return finalize([null, null, null, null]);
        }

        if (remindAgain) {
            state.scrapPromptIssuedFor = null;
        }

        msg._mode = "scrap-skipped";
        return finalize([null, null, null, null]);
    }
    case "start": {
        // START with KPI timestamp init - FIXED
        const now = Date.now();
        const shifts = settings.shifts || [{ start: '06:00', end: '13:00' }];
        const shiftChangeComp = settings.shiftChangeCompensation || 10;
        const lunchBreak = settings.lunchBreakMinutes || 30;


        let totalShiftSeconds = 0;
        shifts.forEach(shift => {
            const [startH, startM] = (shift.start || '06:00').split(':').map(Number);
            const [endH, endM] = (shift.end || '15:00').split(':').map(Number);

            let startMinutes = startH * 60 + startM;
            let endMinutes = endH * 60 + endM;

            if (endMinutes <= startMinutes) {
                endMinutes += 24 * 60;
            }

            totalShiftSeconds += (endMinutes - startMinutes) * 60;
        });
        const compensationSeconds = shifts.length * shiftChangeComp * 60;
        const lunchSeconds = lunchBreak * 60;
        const plannedProductionTime = Math.max(0, totalShiftSeconds - compensationSeconds - lunchSeconds);
        state.plannedProductionTime = plannedProductionTime;

        const existingCycles = Number(state.cycleCount || 0);
        const activeOrderState = state.activeWorkOrder || {};
        const orderGood = Number(activeOrderState.goodParts) || 0;
        const orderScrap = Number(activeOrderState.scrapParts) || 0;

        const hasProgressFlag = state.activeOrderHasProgress;

        const hasProgress = (typeof hasProgressFlag === 'boolean')
            ? hasProgressFlag
            : (
                existingCycles > 0 ||
                (orderGood + orderScrap) > 0
            );

        if (!hasProgress) {
            state.stopTime = 0;
            state.trackingEnabled = true;
            state.productionStarted = true;
            state.kpiStartupMode = true;
            state.kpiBuffer = [];
            state.lastKPIRecordTime = now - 60000;
            state.productionStartTime = now;
            state.lastMachineCycleTime = now;
            state.lastCycleTime = now;
            state.operatingTime = 0;
            state.actualRunTime = 0;
            state.lastStartChangeTime = now;
            state.lastCycleCompletionTime = null;
            state.runSeconds = 0;
            state.stopSeconds = 0;
            state.kpiLastTick = null;
        } else {
            state.trackingEnabled = true;
            state.productionStarted = true;
            state.kpiStartupMode = false;
        }

        const activeOrder = state.activeWorkOrder || {};
        msg._mode = "production-state";

        msg.payload = msg.payload || {};

        msg.trackingEnabled = true;
        msg.productionStarted = true;
        msg.machineOnline = true;

        msg.payload.trackingEnabled = true;
        msg.payload.productionStarted = true;
        msg.payload.machineOnline = true;

        return finalize([null, msg, null, null]);
    }
    case "stop": {
        state.trackingEnabled = false;
        state.productionStarted = false;

        msg._mode = "production-state";
        msg.payload = msg.payload || {};
        msg.trackingEnabled = false;
        msg.productionStarted = false;
        msg.machineOnline = true;
        msg.payload.trackingEnabled = false;
        msg.payload.productionStarted = false;
        msg.payload.machineOnline = true;

        const s = state.lastState || {};
        s.trackingEnabled = false;
        s.productionStarted = false;
        s.tsMs = Date.now();
        state.lastState = s;

        return finalize([null, msg, null, null]);
    }
    case "start-tracking": {
        const activeOrder = state.activeWorkOrder || {};

        if (!activeOrder.id) {
            return finalize([null, { topic: "alert", payload: "Error: No active work order loaded." }, null, null]);
        }

        const now = Date.now();
        state.trackingEnabled = true;

        state.kpiBuffer = [];
        state.lastKPIRecordTime = now - 60000;
        state.lastMachineCycleTime = now;
        state.lastCycleTime = now;
        state.operatingTime = 0.001;

        const stateMsg = {
            _mode: "production-state",
            payload: {
                trackingEnabled: true,
                machineOnline: true
            }
        };

        return finalize([null, stateMsg, null, null]);
    }
    case "start-mold-change": {
        const now = Date.now();
        const p = msg.payload || {};
        const mc = {
            active: true,
            startMs: now,
            endMs: null,
            fromMoldId: p.fromMoldId || null,
            toMoldId: null,
            operator: p.operator || null
        };
        state.moldChange = mc;
        // Disable tracking during mold change so KPI/anomaly are paused
        state.trackingEnabled = false;
        state.productionStarted = false;
        const event = {
            payload: {
                anomaly_type: "mold-change",
                eventType: "mold-change",
                severity: "info",
                requires_ack: false,
                title: "Cambio de molde iniciado",
                description: "Inicio de cambio de molde",
                status: "active",
                tsMs: now,
                data: {
                    status: "active",
                    start_ms: now,
                    from_mold_id: mc.fromMoldId,
                    operator: mc.operator,
                    incidentKey: "mold-change:" + now
                }
            },
            tsMs: now
        };
        const uiMsg = { _mode: "mold-change-status", payload: { active: true, startMs: now, fromMoldId: mc.fromMoldId } };
        return finalize([null, uiMsg, null, null, null, event]);
    }
    case "end-mold-change": {
        const now = Date.now();
        const p = msg.payload || {};
        const mc = state.moldChange || {};
        if (!mc.active) {
            return finalize([null, null, null, null, null, null]);
        }
        const durationSec = Math.max(0, Math.round((now - (mc.startMs || now)) / 1000));
        const closed = {
            active: false,
            startMs: mc.startMs,
            endMs: now,
            fromMoldId: mc.fromMoldId || null,
            toMoldId: p.toMoldId || null,
            durationSec
        };
        state.moldChange = closed;
        const event = {
            payload: {
                anomaly_type: "mold-change",
                eventType: "mold-change",
                severity: "info",
                requires_ack: false,
                title: "Cambio de molde finalizado",
                description: "Duracion: " + Math.round(durationSec / 60) + " min",
                status: "resolved",
                tsMs: now,
                data: {
                    status: "resolved",
                    start_ms: closed.startMs,
                    end_ms: now,
                    duration_sec: durationSec,
                    stoppage_duration_seconds: durationSec,
                    from_mold_id: closed.fromMoldId,
                    to_mold_id: closed.toMoldId,
                    incidentKey: "mold-change:" + (closed.startMs || now)
                }
            },
            tsMs: now
        };
        const uiMsg = { _mode: "mold-change-status", payload: { active: false, endMs: now, durationSec } };
        return finalize([null, uiMsg, null, null, null, event]);
    }

}

const rows = Array.isArray(msg.payload) ? msg.payload : [];

const values = rows
  .map((r) => {
    const id = String(r["Work Order ID"] ?? "").trim();
    if (!id) return null;

    const sku = String(r["SKU"] ?? "").trim();
    const targetQty = Number(r["Target Quantity"]) || 0;
    const cycleTime =
      Number(r["Theoretical Cycle Time (Seconds)"]) || 0;

    return [id, sku, targetQty, cycleTime, "PENDING"];
  })
  .filter(Boolean);

if (!values.length) {
  return null;
}

msg.topic = `
  INSERT INTO work_orders
    (work_order_id, sku, target_qty, cycle_time, status)
  VALUES ?
  ON DUPLICATE KEY UPDATE
    sku = VALUES(sku),
    target_qty = VALUES(target_qty),
    cycle_time = VALUES(cycle_time);
`;

msg.payload = [values];

return msg;

const mode = msg._mode || '';
const started = msg.startOrder || null;
const completed = msg.completeOrder || null;
const state = global.get("state") || {};
const settings = global.get("settings") || {};

// ✨ La WO de la BD es la única fuente de cavidades.
// attachMold solo normaliza nombres entre cavities/cavitiesActive y cavities_total/cavitiesTotal
// para compatibilidad con código que aún lee los nombres viejos.
// YA NO escribe en state.lastMoldActive ni state.moldByWorkOrder (cache global eliminado).
const attachMold = (order) => {
    if (!order || !order.id) return;

    const cavities = Number(
        order.cavitiesActive ??
        order.cavities_active ??
        order.cavities ??
        0
    );
    const total = Number(
        order.cavitiesTotal ??
        order.cavities_total ??
        0
    );

    if (Number.isFinite(cavities) && cavities > 0) {
        order.cavitiesActive = cavities;
        order.cavities = cavities; // alias para código viejo
    }
    if (Number.isFinite(total) && total > 0) {
        order.cavitiesTotal = total;
        order.cavities_total = total; // alias para código viejo
    }
};

const finalize = (ret) => {
    global.set("state", state);
    return ret;
};

const toIsoString = (v) => {
    if (!v) return null;
    if (typeof v === "string") return v;
    if (v instanceof Date) return v.toISOString();
    if (typeof v.toISOString === "function") return v.toISOString();
    if (typeof v.toISO === "function") return v.toISO();
    if (typeof v.format === "function") return v.format();
    return String(v);
};

delete msg._mode;
delete msg.startOrder;
delete msg.completeOrder;
delete msg.action;
delete msg.filename;

// ========================================================
// MODE: UPLOAD
// ========================================================
if (mode === "upload") {
    msg.topic = "uploadStatus";
    msg.payload = { message: "✅ Work orders uploaded successfully." };
    return finalize([msg, null, null, null]);
}

// ========================================================
// MODE: SELECT (Load Work Orders)
// ========================================================
if (mode === "select") {
    const rawRows = Array.isArray(msg.payload) ? msg.payload : [];
    msg.topic = "workOrdersList";
    msg.payload = rawRows.map(row => ({
        id: row.work_order_id ?? row.id ?? "",
        sku: row.sku ?? "",
        target: Number(row.target_qty ?? row.target ?? 0),
        goodParts: Number(row.good_parts ?? row.goodParts ?? 0),
        scrapParts: Number(row.scrap_count ?? row.scrap_parts ?? row.scrapParts ?? 0),
        progressPercent: Number(row.progress_percent ?? row.progress ?? 0),
        status: (row.status ?? "PENDING").toUpperCase(),
        lastUpdateIso: toIsoString(row.updated_at ?? row.last_update),
        cycleTime: Number(row.cycle_time ?? row.theoretical_cycle_time ?? 0)
    }));
    return finalize([msg, null, null, null]);
}

// ========================================================
// MODE: START WORK ORDER
// ========================================================
if (mode === "start") {
    const order = started || {};
    attachMold(order);
    const kpis = msg.kpis || state.currentKPIs || {
        oee: 0, availability: 0, performance: 0, quality: 0
    };

    const homeMsg = {
        topic: "activeWorkOrder",
        payload: {
            id: order.id || "",
            sku: order.sku || "",
            target: Number(order.target) || 0,
            goodParts: Number(order.goodParts) || 0,
            scrapParts: Number(order.scrapParts) || 0,
            cycleTime: Number(order.cycleTime || order.theoreticalCycleTime || 0),
            progressPercent: Number(order.progressPercent) || 0,
            lastUpdateIso: toIsoString(order.lastUpdateIso) || null,
            kpis: kpis
        }
    };

    return finalize([null, homeMsg, null, null]);
}

// ========================================================
// MODE: COMPLETE WORK ORDER
// ========================================================
if (mode === "complete") {
    const homeMsg = { topic: "activeWorkOrder", payload: null };
    return finalize([null, homeMsg, null, null]);
}

// ========================================================
// MODE: CYCLE UPDATE DURING PRODUCTION
// ========================================================
if (mode === "cycle") {
    const cycle = msg.cycle || {};

    const workOrderMsg = {
        topic: "workOrderCycle",
        payload: {
            id: cycle.id || "",
            sku: cycle.sku || "",
            target: Number(cycle.target) || 0,
