    if (!isFinite(v) || isNaN(v)) return 0;
    return Math.max(0, Math.min(100, v));
}

let availability = 0;
let performance = 0;
let quality = 100;
let oee = 0;

// Startup mode: skip KPI emit until first real cycle/state transition
if (kpiStartupMode) {
    global.set("state", state);
    return null;
} else {
    // Availability = Run Time / Scheduled Production Time
    availability = availabilityPct;


    // Performance = (Ideal Cycle Time × Cycles) / Sum of actual cycle times
    const actualCycleTime = Number(state.lastActualCycleTime || 0);
    state.perf = state.perf || { lastCycleCount: 0, runSeconds: 0 };

    // Use same threshold you use for slow-cycle
    const perfThreshold = idealCycleTime * Number(settings.thresholdMultiplier || 1.5);

    if (cycleCount > state.perf.lastCycleCount && actualCycleTime > 0) {
        // Cap at threshold so time beyond becomes downtime, not performance loss
        const perfCycleTime = Math.min(actualCycleTime, perfThreshold);
        state.perf.runSeconds += perfCycleTime;
        state.perf.lastCycleCount = cycleCount;
    }

    if (state.perf.runSeconds > 0 && cycleCount > 0) {
        const idealTime = idealCycleTime * cycleCount;
        performance = (idealTime / state.perf.runSeconds) * 100;
    }

    // Quality = Good Parts / Total Parts
    if (totalParts > 0) {
        quality = (goodParts / totalParts) * 100;
    }

    availability = clampPercent(availability);
    performance  = clampPercent(performance);
    quality      = clampPercent(quality);

    // OEE = A × P × Q
    oee = (availability * performance * quality) / 10000;
}

// Clamp & round to 1 decimal
oee = clampPercent(oee);

msg.kpis = {
    availability: Math.round(availability * 10) / 10,
    performance:  Math.round(performance  * 10) / 10,
    quality:      Math.round(quality      * 10) / 10,
    oee:          Math.round(oee          * 10) / 10
};

