                    delta_percent: Math.round(deltaPercent),
                    micro_threshold_multiplier: microMultiplier,
                    macro_threshold_multiplier: macroMultiplier
                },
                kpi_snapshot: {
                    oee: kpis.oee || 0,
                    availability: kpis.availability || 0,
                    performance: kpis.performance || 0,
                    quality: kpis.quality || 0
                },
                work_order_id: activeOrder.id,
                cycle_count: currentCycleCount,
                tsMs: now
            };

            //node.warn(`[SLOW-CYCLE] ${actualCycleTime.toFixed(1)}s (expected ${theoreticalCycleTime}s)`);

        } /*else if (actualCycleTime >= macroThresholdSec) {
            cycleEvent = {
                anomaly_type: "macrostop",
                severity: "critical",
                requires_ack: true,
                title: "Macrostop Detected",
                description: `Cycle gap ${actualCycleTime.toFixed(1)}s (threshold: ${macroThresholdSec.toFixed(1)}s)`,
                data: {
                    stoppage_duration_seconds: Math.round(actualCycleTime),
                    theoretical_cycle_time: theoreticalCycleTime,
                    micro_threshold_multiplier: microMultiplier,
                    macro_threshold_multiplier: macroMultiplier
                },
                kpi_snapshot: {
                    oee: kpis.oee || 0,
                    availability: kpis.availability || 0,
                    performance: kpis.performance || 0,
                    quality: kpis.quality || 0
                },
                work_order_id: activeOrder.id,
                cycle_count: currentCycleCount,
                tsMs: now,
                status: "resolved"  // Changed to resolved since cycle completed
            };

            node.warn(`[MACROSTOP] ${actualCycleTime.toFixed(1)}s gap detected`);
        }*/

        // FIXED: Always push cycle events (removed duplicate suppression)
        if (cycleEvent) {
            detectedAnomalies.push(cycleEvent);
            //node.warn(`[CYCLE EVENT] Added ${cycleEvent.anomaly_type} to detectedAnomalies`);
        }

        anomalyState.lastCycleEventCount = currentCycleCount;
        anomalyState.lastSlowCycleCount = currentCycleCount;
    }

    // No new cycle yet: start or escalate stoppage
    if (!hasNewCycle && lastCycleTime > 0) {
        // Start stoppage once when we cross micro threshold
        if (!anomalyState.activeStoppageEvent && timeSinceLastCycleSec >= microThresholdSec) {
            const isMacro = timeSinceLastCycleSec >= macroThresholdSec;
            const anomalyType = isMacro ? "macrostop" : "microstop";
            const severity = isMacro ? "critical" : "warning";

            const stoppageEvent = {
                alert_id: `${anomalyType}:${activeOrder.id}:${lastCycleTime}`,
                anomaly_type: anomalyType,
                severity,
                requires_ack: true,
                title: isMacro ? "Macrostop In Progress" : "Microstop In Progress",
                description: `No cycles for ${timeSinceLastCycleSec.toFixed(0)}s (expected cycle every ${theoreticalCycleTime}s)`,
                data: {
                    stoppage_duration_seconds: Math.round(timeSinceLastCycleSec),
                    theoretical_cycle_time: theoreticalCycleTime,
                    last_cycle_timestamp: lastCycleTime,
                    micro_threshold_multiplier: microMultiplier,
                    macro_threshold_multiplier: macroMultiplier
                },
                kpi_snapshot: {
                    oee: kpis.oee || 0,
                    availability: kpis.availability || 0,
                    performance: kpis.performance || 0,
                    quality: kpis.quality || 0
                },
                work_order_id: activeOrder.id,
                cycle_count: cycle.cycles || 0,
                tsMs: now,
                status: "active"
            };

            detectedAnomalies.push(stoppageEvent);
            anomalyState.activeStoppageEvent = stoppageEvent;
            anomalyState.lastStoppageUpdateMs = now;
            //node.warn(`[STOPPAGE START] ${anomalyType} started at ${timeSinceLastCycleSec.toFixed(0)}s`);
        }

        // Escalate micro -> macro once
        if (
            anomalyState.activeStoppageEvent &&
            anomalyState.activeStoppageEvent.anomaly_type === "microstop" &&
            timeSinceLastCycleSec >= macroThresholdSec
        ) {
            detectedAnomalies.push({
                ...anomalyState.activeStoppageEvent,
                status: "resolved",
                resolved_at: now,
                auto_resolved: true,
                requires_ack: false,
                data: {
                    ...anomalyState.activeStoppageEvent.data,
                    stoppage_duration_seconds: Math.round(timeSinceLastCycleSec)
                },
                tsMs: now
            });

            const macroEvent = {
                alert_id: `macrostop:${activeOrder.id}:${lastCycleTime}`,
                anomaly_type: "macrostop",
                severity: "critical",
                requires_ack: true,
                title: "Macrostop In Progress",
                description: `No cycles for ${timeSinceLastCycleSec.toFixed(0)}s (expected cycle every ${theoreticalCycleTime}s)`,
                data: {
                    stoppage_duration_seconds: Math.round(timeSinceLastCycleSec),
                    theoretical_cycle_time: theoreticalCycleTime,
                    last_cycle_timestamp: lastCycleTime,
                    micro_threshold_multiplier: microMultiplier,
                    macro_threshold_multiplier: macroMultiplier
                },
                kpi_snapshot: {
                    oee: kpis.oee || 0,
                    availability: kpis.availability || 0,
                    performance: kpis.performance || 0,
                    quality: kpis.quality || 0
                },
                work_order_id: activeOrder.id,
                cycle_count: cycle.cycles || 0,
                tsMs: now,
                status: "active"
            };

            detectedAnomalies.push(macroEvent);
            anomalyState.activeStoppageEvent = macroEvent;
            anomalyState.lastStoppageUpdateMs = now;
            //node.warn(`[ESCALATION] Microstop -> Macrostop at ${timeSinceLastCycleSec.toFixed(0)}s`);
        }

        // NEW: Send periodic updates for active macrostops
        if (
            anomalyState.activeStoppageEvent &&
            anomalyState.activeStoppageEvent.anomaly_type === "macrostop"
        ) {
            const timeSinceLastUpdate = now - (anomalyState.lastStoppageUpdateMs || 0);

            if (timeSinceLastUpdate >= updateIntervalMs) {
                const prev = anomalyState.activeStoppageEvent;

                // 1) AUTO-ACK the previous active macrostop alert
                const autoAck = {
                    ...prev,
                    status: "resolved",
                    resolved_at: now,
                    auto_resolved: true,
                    requires_ack: false,
                    title: "Macrostop Updated",
                    description: "Auto-acknowledged due to periodic refresh",
                    tsMs: now,
                    is_auto_ack: true
                };

                // 2) Send a NEW active macrostop alert with updated duration + NEW alert_id
                const refreshed = {
                    ...prev,
                    alert_id: `macrostop:${activeOrder.id}:${now}`, // new instance id so UI treats it as new
                    status: "active",
                    requires_ack: true,
                    title: "Macrostop Ongoing",
                    description: `Machine still stopped for ${timeSinceLastCycleSec.toFixed(0)}s (expected cycle every ${theoreticalCycleTime}s)`,
                    data: {
                        ...prev.data,
                        stoppage_duration_seconds: Math.round(timeSinceLastCycleSec)
                    },
                    kpi_snapshot: {
                        oee: kpis.oee || 0,
                        availability: kpis.availability || 0,
                        performance: kpis.performance || 0,
                        quality: kpis.quality || 0
                    },
                    tsMs: now,
                    is_update: true
                };

                detectedAnomalies.push(autoAck, refreshed);

                // IMPORTANT: set the active event to the refreshed one
                anomalyState.activeStoppageEvent = refreshed;
                anomalyState.lastStoppageUpdateMs = now;

                //node.warn(`[MACROSTOP REFRESH] Auto-acked previous, new duration: ${timeSinceLastCycleSec.toFixed(0)}s`);
            }
        }
    }
}



// ============================================================
// TIER 2: OEE DROP DETECTION
// Trigger: OEE falls below threshold
// ============================================================
const currentOEE = Number(kpis.oee) || 0;

if (currentOEE > 0) {
    const lowThreshold = OEE_THRESHOLD;       // e.g. 90
    const recoveryThreshold = OEE_THRESHOLD + 2; // some hysteresis

    if (currentOEE < lowThreshold) {
        // Count consecutive low points
        anomalyState.oeeLowStreak = (anomalyState.oeeLowStreak || 0) + 1;

        const REQUIRED_STREAK = 3; // only alert after 3 bad readings

        // Only fire when we ENTER the bad zone
        if (!anomalyState.activeOeeDrop &&
            anomalyState.oeeLowStreak >= REQUIRED_STREAK) {

            let severity = 'warning';
            if (currentOEE < 75) severity = 'critical';

            detectedAnomalies.push({
                anomaly_type: 'oee-drop',
                severity,
                title: 'OEE Below Threshold',
                description: `OEE at ${currentOEE.toFixed(1)}% (threshold: ${OEE_THRESHOLD}%)`,
                data: {
                    current_oee: currentOEE,
                    threshold: OEE_THRESHOLD,
                    delta: OEE_THRESHOLD - currentOEE
                },
                kpi_snapshot: {
                    oee: kpis.oee || 0,
                    availability: kpis.availability || 0,
                    performance: kpis.performance || 0,
                    quality: kpis.quality || 0
                },
                work_order_id: activeOrder.id,
                cycle_count: cycle.cycles || 0,
                tsMs: now,
                status: 'active'
            });

            anomalyState.activeOeeDrop = true;
            //node.warn(`[ANOMALY] OEE drop started at ${currentOEE.toFixed(1)}%`);
        }

    } else if (currentOEE >= recoveryThreshold) {
        // We are OUT of the bad zone
        anomalyState.oeeLowStreak = 0;

        if (anomalyState.activeOeeDrop) {
            detectedAnomalies.push({
                anomaly_type: 'oee-drop',
                severity: 'info',
                title: 'OEE Recovered',
                description: `OEE recovered to ${currentOEE.toFixed(1)}% (threshold: ${OEE_THRESHOLD}%)`,
                data: {
                    current_oee: currentOEE,
                    threshold: OEE_THRESHOLD
                },
                kpi_snapshot: {
                    oee: kpis.oee || 0,
                    availability: kpis.availability || 0,
                    performance: kpis.performance || 0,
                    quality: kpis.quality || 0
                },
                work_order_id: activeOrder.id,
                cycle_count: cycle.cycles || 0,
                tsMs: now,
                status: 'resolved'
            });

            anomalyState.activeOeeDrop = false;
            //node.warn(`[ANOMALY] OEE recovered to ${currentOEE.toFixed(1)}%`);
        }
    }
}

// Update OEE history for trend analysis
anomalyState.oeeHistory.push({ tsMs: now, value: currentOEE });
if (anomalyState.oeeHistory.length > HISTORY_WINDOW) {
    anomalyState.oeeHistory.shift();  // Keep only recent history
}

// ============================================================
// TIER 2: QUALITY SPIKE DETECTION
// Trigger: Sudden increase in scrap/defect rate
// ============================================================
const totalParts = (cycle.goodParts || 0) + (cycle.scrapParts || 0);
const currentScrapRate =
    totalParts > 0 ? ((cycle.scrapParts || 0) / totalParts) * 100 : 0;

// Keep history for trend
anomalyState.qualityHistory.push({ tsMs: now, value: currentScrapRate });
if (anomalyState.qualityHistory.length > HISTORY_WINDOW) {
    anomalyState.qualityHistory.shift();
}

// Only evaluate when we have enough data and enough volume in this cycle
const MIN_SAMPLES = 5;
const MIN_PARTS_THIS_CYCLE = 10;

if (
    anomalyState.qualityHistory.length >= MIN_SAMPLES &&
    totalParts >= MIN_PARTS_THIS_CYCLE
) {
    const recentHistory = anomalyState.qualityHistory.slice(0, -1); // exclude current
    const avgScrapRate =
        recentHistory.reduce((sum, p) => sum + p.value, 0) /
        recentHistory.length;

    const scrapRateIncrease = currentScrapRate - avgScrapRate;

    const SPIKE_DELTA = QUALITY_SPIKE_THRESHOLD || 5; // your existing config
    const MIN_SCRAP_RATE = 5; // ignore small scrap percentages
    const RECOVERY_MARGIN = 2; // how far back towards avg to consider "recovered"

    // ----- When scrap is HIGH / SPIKE ZONE -----
    if (
        currentScrapRate > MIN_SCRAP_RATE &&
        scrapRateIncrease > SPIKE_DELTA
    ) {
        // count how many consecutive "bad" cycles
        anomalyState.qualityHighStreak =
            (anomalyState.qualityHighStreak || 0) + 1;

        const REQUIRED_STREAK = 2; // require 2 consecutive bad cycles

        // fire ONLY when we ENTER the spike (not every cycle)
        if (
            !anomalyState.activeQualitySpike &&
            anomalyState.qualityHighStreak >= REQUIRED_STREAK
        ) {
            let severity = "warning";
            if (scrapRateIncrease > 10 || currentScrapRate > 15) {
                severity = "critical";
            }

            detectedAnomalies.push({
                anomaly_type: "quality-spike",
                severity,
                title: "Quality Issue Detected",
                description: `Scrap rate at ${currentScrapRate.toFixed(
                    1
                )}% (avg: ${avgScrapRate.toFixed(
                    1
                )}%, +${scrapRateIncrease.toFixed(1)}%)`,
                data: {
                    current_scrap_rate: currentScrapRate,
                    average_scrap_rate: avgScrapRate,
                    increase: scrapRateIncrease,
                    scrap_parts: cycle.scrapParts || 0,
                    total_parts: totalParts
                },
                kpi_snapshot: {
                    oee: kpis.oee || 0,
                    availability: kpis.availability || 0,
                    performance: kpis.performance || 0,
                    quality: kpis.quality || 0
                },
                work_order_id: activeOrder.id,
                cycle_count: cycle.cycles || 0,
                tsMs: now,
                status: "active"
            });

            anomalyState.activeQualitySpike = true;
            /*node.warn(
                `[ANOMALY] Quality spike started: scrap ${currentScrapRate.toFixed(
                    1
                )}% (avg ${avgScrapRate.toFixed(1)}%)`
            );*/
        }
    } else {
        // ----- When scrap is NORMAL / RECOVERY -----
        anomalyState.qualityHighStreak = 0;

        // if we had an active spike, send a single "resolved" event
        if (
            anomalyState.activeQualitySpike &&
            currentScrapRate <= avgScrapRate + RECOVERY_MARGIN
        ) {
            detectedAnomalies.push({
                anomaly_type: "quality-spike",
                severity: "info",
                title: "Quality Issue Resolved",
                description: `Scrap rate back to ${currentScrapRate.toFixed(
                    1
                )}% (avg: ${avgScrapRate.toFixed(1)}%)`,
                data: {
                    current_scrap_rate: currentScrapRate,
                    average_scrap_rate: avgScrapRate
                },
                kpi_snapshot: {
                    oee: kpis.oee || 0,
                    availability: kpis.availability || 0,
                    performance: kpis.performance || 0,
                    quality: kpis.quality || 0
                },
                work_order_id: activeOrder.id,
                cycle_count: cycle.cycles || 0,
                tsMs: now,
                status: "resolved"
            });

            anomalyState.activeQualitySpike = false;
            /*node.warn(
                `[ANOMALY] Quality spike resolved: scrap ${currentScrapRate.toFixed(
                    1
                )}%`
            );*/
        }
    }
}

// ============================================================
// TIER 2: PERFORMANCE DEGRADATION
// Trigger: Consistent underperformance over time
// ============================================================
const currentPerformance = Number(kpis.performance) || 0;
anomalyState.performanceHistory.push({ tsMs: now, value: currentPerformance });
if (anomalyState.performanceHistory.length > HISTORY_WINDOW) {
    anomalyState.performanceHistory.shift();
}

// Check for sustained poor performance (at least 10 data points)
if (anomalyState.performanceHistory.length >= 10) {
    const recent10 = anomalyState.performanceHistory.slice(-10);
    const avgPerformance = recent10.reduce((sum, point) => sum + point.value, 0) / recent10.length;

    const PERF_LOW_THRESHOLD = PERFORMANCE_THRESHOLD;      // 85%
    const PERF_RECOVERY_THRESHOLD = PERFORMANCE_THRESHOLD + 3;  // 88% to recover

    // Check if we're in degraded state
    if (avgPerformance > 0 && avgPerformance < PERF_LOW_THRESHOLD) {
        // Count consecutive low readings
        anomalyState.performanceLowStreak = (anomalyState.performanceLowStreak || 0) + 1;

        const REQUIRED_STREAK = 3;  // Need 3 consecutive low readings

        // Only fire ONCE when entering degraded state
        if (!anomalyState.activePerformanceDegradation &&
            anomalyState.performanceLowStreak >= REQUIRED_STREAK) {

            let severity = 'warning';
            if (avgPerformance < 75) {
                severity = 'critical';
            }

            detectedAnomalies.push({
                anomaly_type: 'performance-degradation',
                severity: severity,
                title: `Performance Degradation`,
                description: `Performance at ${avgPerformance.toFixed(1)}% (sustained over last 10 cycles)`,
                data: {
                    average_performance: avgPerformance,
                    current_performance: currentPerformance,
                    threshold: PERF_LOW_THRESHOLD,
                    sample_size: 10
                },
                kpi_snapshot: {
                    oee: kpis.oee || 0,
                    availability: kpis.availability || 0,
                    performance: kpis.performance || 0,
                    quality: kpis.quality || 0
                },
                work_order_id: activeOrder.id,
                cycle_count: cycle.cycles || 0,
                tsMs: now,
                status: 'active'
            });

            // Mark as active so we don't spam
            anomalyState.activePerformanceDegradation = true;
            //node.warn(`[ANOMALY] Performance degradation STARTED: ${avgPerformance.toFixed(1)}%`);
        }

    } else if (avgPerformance >= PERF_RECOVERY_THRESHOLD) {
        // Performance recovered
        anomalyState.performanceLowStreak = 0;

        // Only send recovery message if we were previously in degraded state
        if (anomalyState.activePerformanceDegradation) {
            detectedAnomalies.push({
                anomaly_type: 'performance-degradation',
                severity: 'info',
                title: 'Performance Recovered',
                description: `Performance recovered to ${avgPerformance.toFixed(1)}% (threshold: ${PERF_LOW_THRESHOLD}%)`,
                data: {
                    average_performance: avgPerformance,
                    current_performance: currentPerformance,
                    threshold: PERF_LOW_THRESHOLD
                },
                kpi_snapshot: {
                    oee: kpis.oee || 0,
                    availability: kpis.availability || 0,
                    performance: kpis.performance || 0,
                    quality: kpis.quality || 0
                },
                work_order_id: activeOrder.id,
                cycle_count: cycle.cycles || 0,
                tsMs: now,
                status: 'resolved'
            });

            anomalyState.activePerformanceDegradation = false;
            //node.warn(`[ANOMALY] Performance degradation RESOLVED: ${avgPerformance.toFixed(1)}%`);
        }
    }
}

// ============================================================
// TIER 3: PREDICTIVE ALERTS (Trend Analysis)
// Predict issues before they become critical
// ============================================================
if (anomalyState.oeeHistory.length >= 15) {
    // Simple linear trend analysis on OEE
    const recent15 = anomalyState.oeeHistory.slice(-15);
    const firstHalf = recent15.slice(0, 7);
    const secondHalf = recent15.slice(-7);

    const avgFirstHalf = firstHalf.reduce((sum, p) => sum + p.value, 0) / firstHalf.length;
    const avgSecondHalf = secondHalf.reduce((sum, p) => sum + p.value, 0) / secondHalf.length;

    const oeeTrend = avgSecondHalf - avgFirstHalf;

    // Predict if OEE is trending downward significantly
    if (oeeTrend < -5 && avgSecondHalf > OEE_THRESHOLD * 0.95 && avgSecondHalf < OEE_THRESHOLD * 1.05) {
        detectedAnomalies.push({
            anomaly_type: 'predictive-oee-decline',
            severity: 'info',
            title: `Declining OEE Trend Detected`,
            description: `OEE trending down ${Math.abs(oeeTrend).toFixed(1)}% over last 15 cycles. Current: ${avgSecondHalf.toFixed(1)}%`,
            data: {
                trend: oeeTrend,
                first_half_avg: avgFirstHalf,
                second_half_avg: avgSecondHalf,
                prediction: 'OEE may drop below threshold soon'
            },
            kpi_snapshot: {
                oee: kpis.oee || 0,
                availability: kpis.availability || 0,
                performance: kpis.performance || 0,
                quality: kpis.quality || 0
            },
            work_order_id: activeOrder.id,
            cycle_count: cycle.cycles || 0,
            tsMs: now
        });

        //node.warn(`[PREDICTIVE] OEE trending down: ${oeeTrend.toFixed(1)}%`);
    }
}

// Update last cycle time for next iteration
anomalyState.lastCycleTime = lastCycleTime;
global.set("anomalyState", anomalyState);
//anomaly.state = anomalyState;
//global.set("anomaly", anomaly);


// ============================================================
// OUTPUT
// ============================================================
const normalizedAnomalies = detectedAnomalies.map(applyDefaultDowntimeReason);

if (normalizedAnomalies.length > 0) {
    node.warn(`[ANOMALY DETECTOR] Detected ${normalizedAnomalies.length} anomaly/ies`);

    normalizedAnomalies.forEach((a, i) => {
        node.warn(`  [${i + 1}] ${a.anomaly_type} - ${a.title} - ${a.status || 'N/A'}`);
    });

    msg.topic = "anomaly-detected";
    msg.payload = normalizedAnomalies;
    msg.originalMsg = msg.originalMsg || null;
    msg._anomaly_source = "anomaly_detector";
    return msg;
}
return null;

// ============================================================
// EVENT LOGGER - SIMPLIFIED (INSERTS ONLY)
// Every anomaly gets inserted as a new row
// ============================================================

const anomalies = msg.payload || [];
const settings = global.get("settings") || {};
const anomalyStateStore = global.get("anomaly") || {};
const reasonsByIncident = anomalyStateStore.reasonsByIncident || {};

if (!Array.isArray(anomalies) || anomalies.length === 0) {
    return null;
}

// SQL escape helper
const esc = (v) => {
    if (v === null || v === undefined) return 'NULL';
    return "'" + String(v).replace(/\\/g, '\\').replace(/'/g, "''") + "'";
};

const dbInserts = [];
const activeAnomalies = [];
const softNotifications = [];  


anomalies.forEach(anomaly => {
    const tsMs = Number(anomaly.tsMs) || Date.now();
    const woId = anomaly.work_order_id || '';
    const aType = anomaly.anomaly_type || 'unknown';
    const sev = anomaly.severity || 'warning';
    const title = anomaly.title || '';
    const desc = anomaly.description || '';
    const dataJson = JSON.stringify(anomaly.data || {});
    const kpiJson = JSON.stringify(anomaly.kpi_snapshot || {});
    const cycle = Number(anomaly.cycle_count) || 0;
    const requiresAck = anomaly.requires_ack !== false;
    const incidentKey = anomaly.incidentKey || (anomaly.data && anomaly.data.last_cycle_timestamp
        ? [aType, woId, String(anomaly.data.last_cycle_timestamp)].join(":")
        : (anomaly.alert_id || null));
    const reason = incidentKey ? (reasonsByIncident[incidentKey] || null) : null;

    // Build INSERT query
    const insertQuery = 
        "INSERT INTO anomaly_events " +
        "(`event_timestamp`, `work_order_id`, `anomaly_type`, `severity`, `title`, `description`, " +
        "`data_json`, `kpi_snapshot_json`, `status`, `cycle_count`, `occurrence_count`, `last_occurrence`) VALUES (" +
        tsMs + ", " +
        esc(woId) + ", " +
        esc(aType) + ", " +
        esc(sev) + ", " +
        esc(title) + ", " +
        esc(desc) + ", " +
        esc(dataJson) + ", " +
        esc(kpiJson) + ", " +
        "'active', " +
        cycle + ", " +
        "1, " +
        tsMs + ")";

    dbInserts.push({ topic: insertQuery, payload: [] });

    // Add to active list for UI
    if (requiresAck) {
        // Hard alerts that go to the panel + require acknowledgment
        activeAnomalies.push({
            event_id: null,
            tsMs: tsMs,
            work_order_id: woId,
            anomaly_type: aType,
            incidentKey: incidentKey || null,
            severity: sev,
            title: title,
            description: desc,
            status: 'active',
            reason: reason,
            kpi_snapshot: anomaly.kpi_snapshot || {}
        });

        node.warn(`[EVENT LOGGER] Inserting ${aType}: ${title} (requires ack)`);
    } else {
        // Soft alerts (e.g. slow-cycle) -> just show a transient popup
        softNotifications.push({
            tsMs: tsMs,
            anomaly_type: aType,
            severity: sev,
            title: title,
            description: desc,
            requires_ack: false
        });

        node.warn(`[EVENT LOGGER] Logging soft anomaly ${aType}: ${title}`);
    }
});

// UI update message
const uiMsg = {
    topic: "anomaly-ui-update",
    payload: {
        activeCount: activeAnomalies.length,
        activeAnomalies: activeAnomalies,
        updates: activeAnomalies.map(a => ({ status: 'new', anomaly: a })),
        softNotifications: softNotifications,
        reasonCatalog: settings.reasonCatalog || null
    }
};

return [dbInserts, uiMsg];

// Initialize OEE alert threshold
const settings = global.get("settings") || {};
const threshold = Number(msg.payload) || 90;
settings.oeeAlertThreshold = threshold;
global.set("settings", settings);

node.warn(`[CONFIG] OEE Alert Threshold set to ${threshold}%`);

return msg;

// ============================================================
// SAVE KPIs TO DATABASE - 1 SNAPSHOT PER CYCLE
// ============================================================

const state = global.get("state") || {};
const kpis = msg.kpis || {};

// Rising edge guard: only save once per cycle
const saveFlag = state.saveKpis || 0;
if (!saveFlag) {
    return null;
}
state.saveKpis = 0;
global.set("state", state);

const dbInserts = [];

const activeOrder = state.activeWorkOrder || {};
const workorder_id = activeOrder.id;
const oee = Number(kpis.oee);
const performance = Number(kpis.performance);
const availability = Number(kpis.availability);
