    const availData = [];
    const perfData = [];
    const qualData = [];

    function bucketSeries(source, size) {
    const bucketSize = size || 5;   // 3 points → 1 smoother point
    if (!Array.isArray(source) || source.length <= bucketSize) return source;

    const result = [];
    for (let i = 0; i < source.length; i += bucketSize) {
        const bucket = source.slice(i, i + bucketSize);
        const avgY = bucket.reduce((sum, p) => sum + Number(p.y || 0), 0) / bucket.length;
        const midPoint = bucket[Math.floor(bucket.length / 2)] || bucket[0];
        result.push({ x: midPoint.x, y: avgY });
    }
    return result;
}


