        availData.push({ x: formattedx_value, y: row.availability_percent });
        perfData.push({ x: formattedx_value, y: row.performance_percent });
        qualData.push({ x: formattedx_value, y: row.quality_percent });
    });

    const smoothOee   = bucketSeries(oeeData, 5);
    const smoothAvail = bucketSeries(availData, 5);
    const smoothPerf  = bucketSeries(perfData, 5);
