  if (!raw || typeof raw !== "object") continue;

  const event = { ...raw };
  const tsMs = typeof event.tsMs === "number" ? event.tsMs : Date.now();

  const incidentKey =
    event.incidentKey ||
    event.incident_key ||
    (event.data && event.data.last_cycle_timestamp
      ? [event.anomaly_type || event.anomalyType || "event",
      event.work_order_id || event.workOrderId || "",
      String(event.data.last_cycle_timestamp)].join(":")
      : null);

  const reasonFromStore = incidentKey && anomaly.reasonsByIncident
    ? anomaly.reasonsByIncident[incidentKey]
    : null;
  if (!event.reason && reasonFromStore) event.reason = reasonFromStore;

  const anomalyType = event.anomaly_type || event.anomalyType || null;
  const isDowntimeType = anomalyType === "microstop" || anomalyType === "macrostop";
  if (!event.downtime) {
    event.downtime = isDowntimeType ? {
      incidentKey: incidentKey || null,
      anomalyType,
      durationSeconds: event.data && Number(event.data.stoppage_duration_seconds) || null
