    (incomingCatalog && incomingCatalog.version) ??
    effective.reasonCatalogVersion ??
    currentCatalog.version ??
    1
  ) || 1;

const hasIncomingCatalog = !!(incomingCatalog && (Array.isArray(incomingCatalog.downtime) || Array.isArray(incomingCatalog.scrap)));
const normalizedIncoming = hasIncomingCatalog ? {
  version: nextCatalogVersion,
  downtime: normalizeCatalogItems(incomingCatalog.downtime || [], "Paro"),
  scrap: normalizeCatalogItems(incomingCatalog.scrap || [], "Scrap")
} : null;

const fallbackCatalog = {
  version: Number(currentCatalog.version || nextCatalogVersion || 1),
  downtime: normalizeCatalogItems(currentCatalog.downtime || [], "Paro"),
  scrap: normalizeCatalogItems(currentCatalog.scrap || [], "Scrap")
};

settings.reasonCatalog = normalizedIncoming || fallbackCatalog;
settings.reasonCatalog.version = Number(settings.reasonCatalog.version || 1);


if (effective.version !== undefined) {
  settings.version = Number(effective.version);
}

global.set("settings", settings);
try {
