const config = global.get("config") || {};
const base = config.cloudBaseUrl;
const apiKey = config.apiKey;
const machineId = config.machineId;

if (!base || !apiKey || !machineId) {
  node.status({ fill: "yellow", shape: "ring", text: "Work orders fetch waiting for pairing" });
  return null;
}

const update = msg.payload || {};
if (update.machineId && update.machineId !== machineId) {
  return null;
}
if (config.orgId && update.orgId && update.orgId !== config.orgId) {
  return null;
}

const baseUrl = String(base).replace(/\/+$/, "");
msg.method = "GET";
msg.url = baseUrl + "/api/work-orders/machines/" + machineId;
msg.headers = {
