}

function intOrNull(value) {
  if (value === null || value === undefined || value === "") return null;
  const n = Number(value);
  if (!Number.isFinite(n) || n < 0) return null;
  return Math.trunc(n);
}

function strOrNull(value, maxLen) {
  if (value === null || value === undefined) return null;
  const s = String(value).trim();
  if (!s) return null;
  return maxLen ? s.slice(0, maxLen) : s;
}

const seen = new Set();
const values = [];

list.forEach((order) => {
  const id = String(
    order.workOrderId || order.id || order.work_order_id || ""
  ).trim();
  if (!id || seen.has(id)) return;
  seen.add(id);

  const sku = String(order.sku || "").trim();

  const targetQtyRaw = order.targetQty ?? order.target_qty ?? order.target ?? 0;
  const cycleTimeRaw = order.cycleTime ?? order.theoreticalCycleTime ?? order.theoretical_cycle_time ?? 0;

  const targetQty = Number.isFinite(Number(targetQtyRaw)) ? Math.trunc(Number(targetQtyRaw)) : 0;
  const cycleTime = Number.isFinite(Number(cycleTimeRaw)) ? Number(cycleTimeRaw) : 0;

  // ✨ NUEVO: leer mold y cavidades
  const mold = strOrNull(order.mold ?? order.moldId ?? order.mold_id, 50);
  const cavitiesTotal = intOrNull(order.cavitiesTotal ?? order.cavities_total);
  const cavitiesActive = intOrNull(order.cavitiesActive ?? order.cavities_active);

  values.push([id, sku, targetQty, cycleTime, "PENDING", mold, cavitiesTotal, cavitiesActive]);
});

if (!values.length) {
  node.status({ fill: "yellow", shape: "ring", text: "No valid work orders" });
  return null;
}

msg.topic = `
  INSERT INTO work_orders
    (work_order_id, sku, target_qty, cycle_time, status, mold, cavities_total, cavities_active)
  VALUES ?
  ON DUPLICATE KEY UPDATE
    sku = VALUES(sku),
    target_qty = VALUES(target_qty),
    cycle_time = VALUES(cycle_time),
    mold = COALESCE(VALUES(mold), mold),
    cavities_total = COALESCE(VALUES(cavities_total), cavities_total),
    cavities_active = COALESCE(VALUES(cavities_active), cavities_active);
`;
msg.payload = [values];
