return msg;

const awo = msg.payload?.activeWorkOrder;
if (awo) {
  const v = awo.lastUpdateIso;

  // If it's already a string, keep it
  if (typeof v === "string") {
    // ok
  } else if (v instanceof Date) {
    awo.lastUpdateIso = v.toISOString();
  } else if (v && typeof v.toISO === "function") {
    // Luxon DateTime
    awo.lastUpdateIso = v.toISO();
  } else if (v && typeof v.toISOString === "function") {
    // Some date-like objects
    awo.lastUpdateIso = v.toISOString();
  } else if (v && typeof v.format === "function") {
    // Moment-like
    awo.lastUpdateIso = v.format();
  } else {
    // Last resort: try to stringify, otherwise null it out
    awo.lastUpdateIso = v ? String(v) : null;
  }
  node.warn(`[lastUpdateIso] typeof=${typeof v} value=${v}`);
  node.warn(`[lastUpdateIso] JSON=${JSON.stringify(v)}`);
}

return msg;

// Build direct heartbeat HTTP request
