    "Content-Type": "application/json",
    "x-api-key": apiKey,
};

// Use the same payload you already build in Online HeartBeat
msg.payload = {
    machineId: msg.machineId,
    tsDevice: msg.tsMs,
    tsMs: msg.tsMs, // device time; same as tsDevice for preprocess
    status: "ONLINE",
    message: "NR heartbeat",
    ip: (config.edgeIp || msg.ip || "192.168.18.33"),
    fwVersion: (config.fwVersion || "raspi-nodered-1.0"),
};

return msg;

/**
 * Machine Cycle Simulator (0/1 square wave with realistic variance)
 *
 * How to use:
 * - Trigger this node ONCE (Inject once after deploy). It will start emitting 0/1 on its own.
 * - To stop: send a message with msg.payload = "stop" (or msg.topic="stop")
 * - To reset state: msg.payload = "reset"
 *
 * Output:
 * - msg.payload = 0 or 1
 */

const CFG = {
    halfPeriodMs: 7250,
    jitterMs: 250,
    perfectRunMs: 30 * 60 * 1000,
    pEnterPerfect: 0,      // was 0.12  — disable perfect runs
    pSlowPhase: 0,         // was 0.10  — disable slow phases
    pMicroStop: 0.5,       // was 0.06  — force frequent microstops
    pMacroStop: 0.2,       // was 0.008 — force frequent macrostops
    microStopMs: [5000, 15000],
    macroStopMs: [60 * 1000, 120 * 1000],  // shorter macros (1-2 min) so you don't wait 8 min
    slowFactor: [1.25, 1.9],
    slowPhaseToggles: [6, 25],
    minGapMicroMs: 10 * 1000,   // was 20s — allow faster retriggering
    minGapMacroMs: 30 * 1000,   // was 60s
};

function randInt(min, max) { return Math.floor(Math.random() * (max - min + 1)) + min; }
function randFloat(min, max) { return Math.random() * (max - min) + min; }
function pickMs(range) { return randInt(range[0], range[1]); }
function clamp(n, a, b) { return Math.max(a, Math.min(b, n)); }

function clearTimer() {
    const t = context.get("timer");
    if (t) clearTimeout(t);
    context.set("timer", null);
    context.set("running", false);
}

if (msg && (msg.payload === "stop" || msg.topic === "stop")) {
    clearTimer();
    node.status({ fill: "grey", shape: "ring", text: "stopped" });
    return null;
}

if (msg && msg.payload === "reset") {
    context.set("state", 0);
    node.status({ fill: "grey", shape: "dot", text: "reset to 0" });
    return null;
}

// Store a template msg (so you can pass machineId/topic/etc. once)
if (msg && typeof msg === "object") {
    const template = Object.assign({}, msg);
    delete template.payload; // we'll overwrite payload each emit
    context.set("template", template);
}

let running = context.get("running") || false;
let timer = context.get("timer");
let state = context.get("state");
if (state === undefined || state === null) state = 0;

let phase = context.get("phase") || { type: "idle", until: 0, slowLeft: 0 };
let lastStopAt = context.get("lastStopAt") || 0;

function decideNextDelayMs() {
    const now = Date.now();

    // Perfect run active
    if (phase.type === "perfect" && now < phase.until) {
        const jitter = randInt(-CFG.jitterMs, CFG.jitterMs);
        return clamp(CFG.halfPeriodMs + jitter, 300, 30 * 60 * 1000);
    }

    // Slow phase active (counted in toggles)
    if (phase.type === "slow" && phase.slowLeft > 0) {
        phase.slowLeft -= 1;
        context.set("phase", phase);

        const factor = randFloat(CFG.slowFactor[0], CFG.slowFactor[1]);
        const jitter = randInt(-CFG.jitterMs, CFG.jitterMs);
        node.status({ fill: "blue", shape: "dot", text: `slow (${phase.slowLeft} left)` });
        return clamp(Math.round(CFG.halfPeriodMs * factor) + jitter, 300, 30 * 60 * 1000);
    }

    // Phase ended → maybe enter a new perfect run
    if (Math.random() < CFG.pEnterPerfect) {
        phase = { type: "perfect", until: now + CFG.perfectRunMs, slowLeft: 0 };
        context.set("phase", phase);
        node.status({ fill: "green", shape: "dot", text: "perfect run" });
        return decideNextDelayMs();
    }

    // Event selection (macro > micro > slow > normal)
    const sinceStop = now - lastStopAt;

    if (sinceStop > CFG.minGapMacroMs && Math.random() < CFG.pMacroStop) {
        lastStopAt = now;
        context.set("lastStopAt", lastStopAt);
        node.status({ fill: "red", shape: "dot", text: "MACRO STOP" });
        return pickMs(CFG.macroStopMs);
    }

    if (sinceStop > CFG.minGapMicroMs && Math.random() < CFG.pMicroStop) {
        lastStopAt = now;
        context.set("lastStopAt", lastStopAt);
        node.status({ fill: "yellow", shape: "dot", text: "micro stop" });
        return pickMs(CFG.microStopMs);
    }

    if (Math.random() < CFG.pSlowPhase) {
        phase = { type: "slow", until: 0, slowLeft: randInt(CFG.slowPhaseToggles[0], CFG.slowPhaseToggles[1]) };
        context.set("phase", phase);
        return decideNextDelayMs();
    }

    // Normal running
    node.status({ fill: "green", shape: "dot", text: "running" });
    const jitter = randInt(-CFG.jitterMs, CFG.jitterMs);
    return clamp(CFG.halfPeriodMs + jitter, 300, 30 * 60 * 1000);
}

function emitTick() {
    // Toggle 0/1
    state = state ? 0 : 1;
    context.set("state", state);

    const template = context.get("template") || {};
    const out = Object.assign({}, template, { payload: state });

    node.send(out);

    // Schedule next emission
    const delay = decideNextDelayMs();
    const t = setTimeout(emitTick, delay);
    context.set("timer", t);
}

if (!running) {
    context.set("running", true);
    node.status({ fill: "green", shape: "dot", text: "started" });
}

// Don’t start multiple timers if you accidentally keep the old repeating inject
// before
// after — always start fresh on trigger; ignore stale post-deploy refs
clearTimeout(context.get("timer"));
context.set("timer", setTimeout(emitTick, 100));

return null;

msg.topic = `
SELECT machine_id, api_key, org_id, cloud_base_url
FROM current_config
WHERE machine_id IS NOT NULL AND machine_id <> '' AND api_key IS NOT NULL AND api_key <> ''
ORDER BY updated_at DESC
LIMIT 1;
`.trim();
msg.payload = [];
return msg;

const rows = msg.payload;

if (!Array.isArray(rows) || rows.length === 0) {
    msg._configRetry = (msg._configRetry || 0) + 1;
    msg._configLoaded = false;
    return [null, msg]; // retry path
}

const row = rows[0] || {};
const machineId = (row.machine_id || "").toString().trim();
const apiKey = (row.api_key || "").toString().trim();

if (!machineId || !apiKey) {
    msg._configRetry = (msg._configRetry || 0) + 1;
    msg._configLoaded = false;
    return [null, msg]; // retry path
}

if (msg._configRetry > 12) return [null, null]; // optional stop after 12 tries

const config = global.get("config") || {};
config.machineId = machineId;
config.apiKey = apiKey;
if (row.org_id) config.orgId = row.org_id;
if (row.cloud_base_url) config.cloudBaseUrl = row.cloud_base_url;
if (config.settingsReadOnly === undefined) config.settingsReadOnly = true;
if (!config.mqttTopicPrefix) config.mqttTopicPrefix = "mis";

global.set("config", config);
msg._configLoaded = true;
return [msg, null];

// KPI Gate: 1/min throttle + dedupe + fresh timestamp
const now = Date.now();
const minIntervalMs = 60000;

const payload = msg.outbox?.payload;
if (!payload) return null;

// stable signature (no tsMs)
const sig = JSON.stringify({
    workOrderId: payload.activeWorkOrder?.id || null,
    cycle_count: payload.cycle_count || 0,
    good_parts: payload.good_parts || 0,
    scrap_parts: payload.scrap_parts || 0,
    cavities: payload.cavities || null,
    cycleTime: payload.cycleTime || 0,
    actualCycleTime: payload.actualCycleTime || 0,
    trackingEnabled: !!payload.trackingEnabled,
    productionStarted: !!payload.productionStarted,
    kpis: payload.kpis || {},
});

const lastSentAt = flow.get("kpi_lastSentAt") || 0;
const lastSig = flow.get("kpi_lastSig") || "";

// Drop if too soon and unchanged
if ((now - lastSentAt) < minIntervalMs && sig === lastSig) {
    return null;
}

// Update gate state
flow.set("kpi_lastSentAt", now);
flow.set("kpi_lastSig", sig);

// Ensure fresh timestamp to avoid timeline weirdness
payload.tsMs = now;
msg.outbox.payload = payload;
msg.tsMs = now;

return msg;

// Build KPI Minute Snapshot (single source of KPI outbox)
const config = global.get("config") || {};
const state = global.get("state") || {};
const machineId = config.machineId;
if (!machineId) return null;

const now = Date.now();
// Optional: align to minute boundary for clean timeline
const tsMs = now - (now % 60000);

const rawActive = state.activeWorkOrder || null;
const active = rawActive ? { ...rawActive } : null;

// Normalize activeWorkOrder.lastUpdateIso to string if present
if (active && active.lastUpdateIso != null) {
  const v = active.lastUpdateIso;
  if (typeof v === "string") {
    // ok
  } else if (v instanceof Date) {
    active.lastUpdateIso = v.toISOString();
  } else if (typeof v === "number") {
    active.lastUpdateIso = new Date(v).toISOString();
  } else if (v && typeof v.toISOString === "function") {
    active.lastUpdateIso = v.toISOString();
  } else if (v && typeof v.toISO === "function") {
    active.lastUpdateIso = v.toISO();
  } else if (v && typeof v.format === "function") {
    active.lastUpdateIso = v.format();
  } else {
    delete active.lastUpdateIso; // avoid invalid payload
  }
}

const kpis = state.currentKPIs || { oee: 0, availability: 0, performance: 0, quality: 0 };

const cavitiesRaw = Number(
  active?.cavities ??
  state.lastMoldActive ??
  0
);
const cavities = cavitiesRaw > 0 ? cavitiesRaw : null;

msg.machineId = machineId;
msg.tsMs = tsMs;

msg.outbox = {
  type: "kpi",
  payload: {
    tsMs,
    activeWorkOrder: active,
    cycle_count: Number(state.cycleCount ?? 0),
    good_parts: Number(active?.goodParts ?? 0),
    scrap_parts: Number(active?.scrapParts ?? 0),
    cavities,
    cycleTime: Number(active?.cycleTime ?? state.lastCycleTime ?? 0),
    actualCycleTime: Number(state.lastActualCycleTime ?? 0),
    trackingEnabled: !!state.trackingEnabled,
    productionStarted: !!state.productionStarted,
    kpis,
  },
};

return msg;

// Después del UPDATE...status='sending', leer las filas que acabamos de reservar
msg.topic = `
SELECT id, machine_id, msg_type, endpoint, schema_version, seq, ts_device_ms,
       payload_json, attempts, next_attempt_at
FROM outbox_messages
WHERE status='sending'
ORDER BY id ASC
LIMIT 25;
`.trim();

msg._stage = "fetch";
return msg;

flow.set("publisherBusy", false);
node.status({ fill: "grey", shape: "dot", text: "idle" });
return null;

msg.topic = `
UPDATE outbox_messages
SET status=?
WHERE status=?
  AND updated_at < DATE_SUB(NOW(), INTERVAL ? SECOND);
`.trim();

msg.payload = ['pending', 'sending', 60];

flow.set("publisherBusy", false);
return msg;

const state = global.get("state") || {};
node.warn("activeWorkOrder: " + JSON.stringify(state.activeWorkOrder, null, 2));
node.warn("trackingEnabled: " + state.trackingEnabled);
node.warn("productionStarted: " + state.productionStarted);
return null;

const state = global.get("state") || {};
node.warn("activeWorkOrder.id: " + state.activeWorkOrder?.id);
node.warn("cavitiesActive: " + state.activeWorkOrder?.cavitiesActive);
node.warn("trackingEnabled: " + state.trackingEnabled);
node.warn("productionStarted: " + state.productionStarted);
node.warn("cycleCount: " + state.cycleCount);
return null;

const state = global.get("state") || {};
node.warn("=== DIAGNÓSTICO STATE ===");
node.warn("activeWorkOrder.id: " + state.activeWorkOrder?.id);
node.warn("cycleCount: " + state.cycleCount);
node.warn("trackingEnabled: " + state.trackingEnabled);
node.warn("productionStarted: " + state.productionStarted);
node.warn("flow.lastMachineState: " + flow.get("lastMachineState"));
return null;

const state = global.get("state") || {};
state.activeWorkOrder = null;
state.activeOrderId = null;
state.activeOrderHasProgress = false;
state.cycleCount = 0;
state.trackingEnabled = false;
state.productionStarted = false;
state.lastState = {
    ...(state.lastState || {}),
    activeWorkOrder: null,
    cycleCount: 0,
    goodParts: 0,
    scrapParts: 0,
    trackingEnabled: false,
    productionStarted: false,
    tsMs: Date.now()
};
delete state.lastMoldActive;
delete state.lastMoldTotal;
delete state.moldByWorkOrder;
global.set("state", state);
global.set("moldCache", null);
flow.set("lastMachineState", 0);
node.warn("State limpiado");
return null;

// Test: mandar SOLO machineStatus, sin nada más
return [{
    topic: "machineStatus",
    payload: {
        machineOnline: true,
        productionStarted: false,
        trackingEnabled: false
    }
}];
